import { describe, it, expect, vi, beforeEach } from 'vitest'
import { screen } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { renderWithMantine } from '@/test/render'
import { ErrorBoundary } from './ErrorBoundary'

const mockCapture = vi.fn()

vi.mock('@/lib/posthog', () => ({
  posthog: { capture: mockCapture },
  posthogEnabled: true,
}))

function ThrowingComponent({ error }: { error: Error }) {
  throw error
}

function GoodComponent() {
  return <div>Everything is fine</div>
}

describe('ErrorBoundary', () => {
  beforeEach(() => {
    mockCapture.mockClear()
    vi.spyOn(console, 'error').mockImplementation(() => {})
  })

  it('renders children when no error occurs', () => {
    renderWithMantine(
      <ErrorBoundary>
        <GoodComponent />
      </ErrorBoundary>,
    )
    expect(screen.getByText('Everything is fine')).toBeInTheDocument()
  })

  it('renders fallback UI when a child throws', () => {
    const error = new Error('Test render error')
    renderWithMantine(
      <ErrorBoundary>
        <ThrowingComponent error={error} />
      </ErrorBoundary>,
    )
    expect(screen.getByText('Something went wrong')).toBeInTheDocument()
    expect(screen.getByText(/unexpected error/i)).toBeInTheDocument()
    expect(screen.getByRole('button', { name: /reload/i })).toBeInTheDocument()
  })

  it('captures exception to PostHog on render error', () => {
    const error = new Error('PostHog capture test')
    renderWithMantine(
      <ErrorBoundary>
        <ThrowingComponent error={error} />
      </ErrorBoundary>,
    )
    expect(mockCapture).toHaveBeenCalledWith('$exception', expect.objectContaining({
      $exception_message: 'PostHog capture test',
      $exception_type: 'Error',
      $exception_source: 'react_error_boundary',
    }))
  })

  it('reloads the page when reload button is clicked', async () => {
    const reloadMock = vi.fn()
    Object.defineProperty(window, 'location', {
      value: { reload: reloadMock },
      writable: true,
    })

    const error = new Error('Test error')
    renderWithMantine(
      <ErrorBoundary>
        <ThrowingComponent error={error} />
      </ErrorBoundary>,
    )

    await userEvent.click(screen.getByRole('button', { name: /reload/i }))
    expect(reloadMock).toHaveBeenCalled()
  })
})

describe('ErrorBoundary (disabled)', () => {
  beforeEach(() => {
    mockCapture.mockClear()
    vi.spyOn(console, 'error').mockImplementation(() => {})
  })

  it('renders fallback but does not capture when posthogEnabled is false', async () => {
    const { posthogEnabled: _orig, ...rest } = await import('@/lib/posthog')
    vi.doMock('@/lib/posthog', () => ({
      ...rest,
      posthogEnabled: false,
      posthog: { capture: mockCapture },
    }))

    const error = new Error('Disabled test')
    renderWithMantine(
      <ErrorBoundary>
        <ThrowingComponent error={error} />
      </ErrorBoundary>,
    )
    expect(screen.getByText('Something went wrong')).toBeInTheDocument()
  })
})

