// Package posthog provides PostHog analytics integration for the API server.
// When POSTHOG_API_KEY is absent, all functions return no-op values.
package posthog

import (
	"context"
	"log/slog"

	ph "github.com/posthog/posthog-go"
)

// Client wraps a posthog.Client with graceful no-op behavior.
type Client struct {
	inner ph.Client
}

// New creates a PostHog client. Returns a no-op client if apiKey is empty.
func New(apiKey, host string) (*Client, error) {
	if apiKey == "" {
		slog.Info("posthog: disabled (POSTHOG_API_KEY not set)")
		return &Client{}, nil
	}

	endpoint := host
	if endpoint == "" {
		endpoint = ph.DefaultEndpoint
	}

	inner, err := ph.NewWithConfig(apiKey, ph.Config{
		Endpoint: endpoint,
	})
	if err != nil {
		return nil, err
	}

	slog.Info("posthog: initialized", "endpoint", endpoint)
	return &Client{inner: inner}, nil
}

// Enabled reports whether PostHog is active.
func (c *Client) Enabled() bool {
	return c.inner != nil
}

// Inner returns the underlying posthog.Client for direct use, or nil if disabled.
func (c *Client) Inner() ph.Client {
	return c.inner
}

// WrapSlogHandler wraps a slog.Handler with PostHog exception capture.
// Returns the handler unchanged if PostHog is disabled.
func (c *Client) WrapSlogHandler(h slog.Handler) slog.Handler {
	if c.inner == nil {
		return h
	}
	return ph.NewSlogCaptureHandler(h, c.inner,
		ph.WithDistinctIDFn(func(_ context.Context, _ slog.Record) string {
			return "kapow-api"
		}),
	)
}

// Close flushes pending events and shuts down the client.
func (c *Client) Close() error {
	if c.inner == nil {
		return nil
	}
	return c.inner.Close()
}

