  1→package main
  2→
  3→import (
  4→	"context"
  5→	"flag"
  6→	"fmt"
  7→	"log/slog"
  8→	"time"
  9→
 10→	"github.com/jackc/pgx/v5/pgxpool"
 11→	"github.com/ketang/kapow/tools/kapow/internal/config"
 12→	"github.com/ketang/kapow/tools/kapow/internal/fetch"
 13→)
 14→
 15→// Importer defines the interface that all data importers must implement.
 16→type Importer interface {
 17→	// Name returns the subcommand name (e.g. "nces", "rankings").
 18→	Name() string
 19→	// Description returns a short human-readable description.
 20→	Description() string
 21→	// Dependencies returns names of importers that must run before this one.
 22→	Dependencies() []string
 23→	// RegisterFlags adds importer-specific flags to the given FlagSet.
 24→	RegisterFlags(fs *flag.FlagSet)
 25→	// Run executes the import. It may use the pool for DB operations and the
 26→	// fetcher for downloading source data.
 27→	Run(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, fetcher *fetch.Fetcher) error
 28→}
 29→
 30→// registry holds all registered importers keyed by name.
 31→var registry = map[string]Importer{}
 32→
 33→// Register adds an importer to the registry. Panics on duplicate name.
 34→func Register(imp Importer) {
 35→	name := imp.Name()
 36→	if _, exists := registry[name]; exists {
 37→		panic(fmt.Sprintf("importer: duplicate registration: %s", name))
 38→	}
 39→	registry[name] = imp
 40→}
 41→
 42→// Get returns a registered importer by name, or nil if not found.
 43→func Get(name string) Importer {
 44→	return registry[name]
 45→}
 46→
 47→// All returns all registered importers.
 48→func All() map[string]Importer {
 49→	return registry
 50→}
 51→
 52→// RunAll executes all importers in dependency order.
 53→func RunAll(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, fetcher *fetch.Fetcher, skip, only map[string]bool) error {
 54→	ordered, err := topoSort(registry)
 55→	if err != nil {
 56→		return err
 57→	}
 58→
 59→	for _, imp := range ordered {
 60→		name := imp.Name()
 61→		if len(only) > 0 && !only[name] {
 62→			slog.Info("run-all: skipping (not in --only)", "importer", name)
 63→			continue
 64→		}
 65→		if skip[name] {
 66→			slog.Info("run-all: skipping (in --skip)", "importer", name)
 67→			continue
 68→		}
 69→
 70→		slog.Info("run-all: starting", "importer", name)
 71→		start := time.Now()
 72→		if err := imp.Run(ctx, cfg, pool, fetcher); err != nil {
 73→			return fmt.Errorf("run-all: %s: %w", name, err)
 74→		}
 75→		slog.Info("run-all: completed", "importer", name, "duration", time.Since(start).Round(time.Millisecond))
 76→	}
 77→
 78→	return nil
 79→}
