package main

import (
	"context"
	"flag"
	"fmt"
	"log/slog"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/ketang/kapow/tools/kapow/internal/config"
	"github.com/ketang/kapow/tools/kapow/internal/fetch"
)

// Importer defines the interface that all data importers must implement.
type Importer interface {
	// Name returns the subcommand name (e.g. "nces", "rankings").
	Name() string
	// Description returns a short human-readable description.
	Description() string
	// Dependencies returns names of importers that must run before this one.
	Dependencies() []string
	// RegisterFlags adds importer-specific flags to the given FlagSet.
	RegisterFlags(fs *flag.FlagSet)
	// Run executes the import. It may use the pool for DB operations and the
	// fetcher for downloading source data.
	Run(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, fetcher *fetch.Fetcher) error
}

// registry holds all registered importers keyed by name.
var registry = map[string]Importer{}

// Register adds an importer to the registry. Panics on duplicate name.
func Register(imp Importer) {
	name := imp.Name()
	if _, exists := registry[name]; exists {
		panic(fmt.Sprintf("importer: duplicate registration: %s", name))
	}
	registry[name] = imp
}

// Get returns a registered importer by name, or nil if not found.
func Get(name string) Importer {
	return registry[name]
}

// All returns all registered importers.
func All() map[string]Importer {
	return registry
}

// RunAll executes all importers in dependency order.
func RunAll(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, fetcher *fetch.Fetcher, skip, only map[string]bool) error {
	ordered, err := topoSort(registry)
	if err != nil {
		return err
	}

	for _, imp := range ordered {
		name := imp.Name()
		if len(only) > 0 && !only[name] {
			slog.Info("run-all: skipping (not in --only)", "importer", name)
			continue
		}
		if skip[name] {
			slog.Info("run-all: skipping (in --skip)", "importer", name)
			continue
		}

		slog.Info("run-all: starting", "importer", name)
		start := time.Now()
		if err := imp.Run(ctx, cfg, pool, fetcher); err != nil {
			return fmt.Errorf("run-all: %s: %w", name, err)
		}
		slog.Info("run-all: completed", "importer", name, "duration", time.Since(start).Round(time.Millisecond))
	}

	return nil
}

// topoSort returns importers in dependency order using Kahn's algorithm.
func topoSort(importers map[string]Importer) ([]Importer, error) {
	// Build in-degree map and adjacency list.
	inDegree := make(map[string]int)
	dependents := make(map[string][]string) // dep -> list of importers that depend on it

	for name, imp := range importers {
		if _, ok := inDegree[name]; !ok {
			inDegree[name] = 0
		}
		for _, dep := range imp.Dependencies() {
			inDegree[name]++
			dependents[dep] = append(dependents[dep], name)
		}
	}

	// Start with importers that have no dependencies.
	var queue []string
	for name, deg := range inDegree {
		if deg == 0 {
			queue = append(queue, name)
		}
	}

	var result []Importer
	for len(queue) > 0 {
		name := queue[0]
		queue = queue[1:]
		if imp, ok := importers[name]; ok {
			result = append(result, imp)
		}
		for _, dep := range dependents[name] {
			inDegree[dep]--
			if inDegree[dep] == 0 {
				queue = append(queue, dep)
			}
		}
	}

	if len(result) != len(importers) {
		return nil, fmt.Errorf("importer: circular dependency detected")
	}

	return result, nil
}

