 16→const (
 17→	bigfutureBaseURL = "https://bigfuture.collegeboard.org/colleges/"
 18→	bigfuturePageType = "bigfuture"
 19→)
 20→
 21→// BigFutureData holds the admissions-related fields from BigFuture's
 22→// __NEXT_DATA__ JSON (props.pageProps.collegeData).
 23→type BigFutureData struct {
 24→	OrgID                        string   `json:"orgId"`
 25→	DICode                       string   `json:"diCode"`
 26→	IPEDSId                      string   `json:"ipedsId"`
 27→	EarlyDecision                bool     `json:"earlyDecision"`
 28→	EarlyDecisionDate            string   `json:"earlyDecisionDate"`
 29→	EarlyActionDate              string   `json:"earlyActionDate"`
 30→	RegularDecisionDate          string   `json:"regularDecisionDate"`
 31→	NotificationDate             string   `json:"notificationDate"`
 32→	ResponseDeadline             string   `json:"responseDeadline"`
 33→	FinancialAidRegularDeadline  string   `json:"financialAidApplicationRegularDeadline"`
 34→	FinancialAidPriorityDeadline string   `json:"financialAidApplicationPriorityDeadline"`
 35→	ApplicationSiteURL           string   `json:"applicationSiteUrl"`
 36→	ApplicationsAccepted         []string `json:"applicationsAccepted"`
 37→}
 38→
 39→// nextDataEnvelope mirrors the __NEXT_DATA__ JSON structure down to collegeData.
 40→type nextDataEnvelope struct {
 41→	Props struct {
 42→		PageProps struct {
 43→			CollegeData BigFutureData `json:"collegeData"`
 44→		} `json:"pageProps"`
 45→	} `json:"props"`
 46→}
 47→
 48→// BigFutureURL returns the full BigFuture URL for a given slug.
 49→func BigFutureURL(slug string) string {
 50→	return bigfutureBaseURL + slug
 51→}
 52→
 53→// FetchPage performs an HTTP GET to fetch a BigFuture college page and returns
 54→// the raw HTML bytes.
 55→func FetchPage(ctx context.Context, client *http.Client, slug string) ([]byte, int, error) {
 56→	url := BigFutureURL(slug)
 57→
 58→	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
 59→	if err != nil {
 60→		return nil, 0, fmt.Errorf("deadlines: bigfuture: create request %s: %w", slug, err)
 61→	}
 62→	req.Header.Set("User-Agent", "Kapow/1.0 (+https://github.com/ketang/kapow)")
 63→	req.Header.Set("Accept", "text/html")
 64→
 65→	resp, err := client.Do(req)
 66→	if err != nil {
 67→		return nil, 0, fmt.Errorf("deadlines: bigfuture: fetch %s: %w", slug, err)
 68→	}
 69→	defer resp.Body.Close()
 70→
 71→	body, err := io.ReadAll(resp.Body)
 72→	if err != nil {
 73→		return nil, resp.StatusCode, fmt.Errorf("deadlines: bigfuture: read body %s: %w", slug, err)
 74→	}
 75→
 76→	if resp.StatusCode != http.StatusOK {
 77→		return nil, resp.StatusCode, fmt.Errorf("deadlines: bigfuture: %s returned status %d", slug, resp.StatusCode)
 78→	}
 79→
 80→	return body, resp.StatusCode, nil
 81→}
