 83→var (
 84→	nextDataStart = []byte(`<script id="__NEXT_DATA__" type="application/json">`)
 85→	nextDataEnd   = []byte(`</script>`)
 86→)
 87→
 88→// ParseNextData extracts the __NEXT_DATA__ JSON from BigFuture HTML and
 89→// returns the parsed college data.
 90→func ParseNextData(html []byte) (*BigFutureData, error) {
 91→	startIdx := bytes.Index(html, nextDataStart)
 92→	if startIdx < 0 {
 93→		return nil, fmt.Errorf("deadlines: bigfuture: __NEXT_DATA__ script tag not found")
 94→	}
 95→	jsonStart := startIdx + len(nextDataStart)
 96→
 97→	endIdx := bytes.Index(html[jsonStart:], nextDataEnd)
 98→	if endIdx < 0 {
 99→		return nil, fmt.Errorf("deadlines: bigfuture: __NEXT_DATA__ closing script tag not found")
100→	}
101→
102→	jsonBytes := html[jsonStart : jsonStart+endIdx]
103→
104→	var envelope nextDataEnvelope
105→	if err := json.Unmarshal(jsonBytes, &envelope); err != nil {
106→		return nil, fmt.Errorf("deadlines: bigfuture: parse __NEXT_DATA__ JSON: %w", err)
107→	}
108→
109→	data := envelope.Props.PageProps.CollegeData
110→	return &data, nil
111→}
112→
113→// ToDeadlineData converts BigFuture data into the canonical DeadlineData format.
114→// The year parameter is the admission cycle year (e.g., 2026 for Fall 2026 entry).
115→func ToDeadlineData(bf *BigFutureData, year int) DeadlineData {
116→	sourceURL := BigFutureURL(slugFromOrgID(bf.OrgID, bf.DICode))
117→	now := time.Now().UTC().Format(time.RFC3339)
118→
119→	dd := DeadlineData{
120→		Plans:            make(map[string]DeadlinePlan),
121→		HasEarlyDecision: bf.EarlyDecision,
122→		HasEarlyAction:   bf.EarlyActionDate != "" && bf.EarlyActionDate != "null",
123→		SourceURLs:       []string{sourceURL},
124→		ExtractedAt:      now,
125→		BigfutureID:      bf.OrgID,
126→	}
127→
128→	// Early Decision
129→	if bf.EarlyDecision && bf.EarlyDecisionDate != "" {
130→		if d := convertDate(bf.EarlyDecisionDate, year); d != "" {
131→			dd.Plans[PlanEarlyDecision1] = DeadlinePlan{
132→				Deadline:   d,
133→				Binding:    true,
134→				SourceURL:  sourceURL,
135→				Confidence: "medium",
136→			}
137→		}
138→	}
139→
140→	// Early Action
141→	if bf.EarlyActionDate != "" {
142→		if d := convertDate(bf.EarlyActionDate, year); d != "" {
143→			dd.Plans[PlanEarlyAction] = DeadlinePlan{
144→				Deadline:   d,
145→				SourceURL:  sourceURL,
146→				Confidence: "medium",
147→			}
148→		}
149→	}
150→
151→	// Regular Decision
152→	if bf.RegularDecisionDate != "" {
153→		plan := DeadlinePlan{
154→			SourceURL:  sourceURL,
155→			Confidence: "medium",
156→		}
157→		if d := convertDate(bf.RegularDecisionDate, year+1); d != "" {
158→			plan.Deadline = d
159→		}
160→		// Notification date goes on the regular plan.
161→		if d := convertDate(bf.NotificationDate, year+1); d != "" {
162→			plan.Notification = d
163→		}
164→		if plan.Deadline != "" || plan.Notification != "" {
165→			dd.Plans[PlanRegular] = plan
166→		}
167→	}
168→
169→	return dd
170→}
171→
172→// convertDate converts a BigFuture date string (MM/DD/9999) to YYYY-MM-DD
173→// using the given year. Returns empty string for null, empty, or unparseable dates.
174→func convertDate(s string, year int) string {
175→	s = strings.TrimSpace(s)
176→	if s == "" || s == "null" {
177→		return ""
178→	}
179→
180→	// Expected format: MM/DD/YYYY (where YYYY is often 9999).
181→	parts := strings.Split(s, "/")
182→	if len(parts) != 3 {
183→		return ""
184→	}
185→
186→	month := parts[0]
187→	day := parts[1]
188→
189→	// Validate month and day are numeric and in range.
190→	if len(month) < 1 || len(month) > 2 || len(day) < 1 || len(day) > 2 {
191→		return ""
192→	}
193→
194→	return fmt.Sprintf("%04d-%s-%s", year, zeroPad(month), zeroPad(day))
195→}
196→
197→// zeroPad ensures a 1-2 digit string is zero-padded to 2 digits.
198→func zeroPad(s string) string {
199→	if len(s) == 1 {
200→		return "0" + s
201→	}
202→	return s
203→}
204→
205→// slugFromOrgID is a fallback slug builder when we only have IDs, not a name.
206→func slugFromOrgID(orgID, diCode string) string {
207→	if orgID != "" {
208→		return orgID
209→	}
210→	return diCode
211→}
212→
213→var slugReplacer = regexp.MustCompile(`[^a-z0-9]+`)
214→
215→// SlugFromName converts an institution name to a BigFuture-style kebab-case slug.
216→func SlugFromName(name string) string {
217→	// Lowercase.
218→	s := strings.ToLower(name)
219→
220→	// Remove apostrophes and periods (BigFuture strips these rather than
221→	// replacing with hyphens).
222→	s = strings.NewReplacer("'", "", "'", "", ".", "").Replace(s)
223→
224→	// Replace any run of non-alphanumeric characters with a single hyphen.
225→	s = slugReplacer.ReplaceAllString(s, "-")
226→
227→	// Trim leading/trailing hyphens.
228→	s = strings.Trim(s, "-")
229→
230→	// Strip any remaining non-ASCII (safety net).
231→	s = strings.Map(func(r rune) rune {
232→		if r > unicode.MaxASCII {
233→			return -1
234→		}
235→		return r
236→	}, s)
237→
238→	return s
239→}
