  1→package main
  2→
  3→import (
  4→	"context"
  5→	"encoding/json"
  6→	"errors"
  7→	"flag"
  8→	"fmt"
  9→	"log/slog"
 10→	"sort"
 11→	"strings"
 12→	"time"
 13→
 14→	"github.com/jackc/pgx/v5/pgxpool"
 15→	"github.com/ketang/kapow/tools/kapow/internal/config"
 16→	"github.com/ketang/kapow/tools/kapow/internal/dbutil"
 17→	"github.com/ketang/kapow/tools/kapow/internal/fetch"
 18→	"github.com/ketang/kapow/tools/kapow/internal/namematch"
 19→	"github.com/ketang/kapow/tools/kapow/internal/platform"
 20→	"github.com/ketang/kapow/tools/kapow/internal/scraper"
 21→)
 22→
 23→func init() {
 24→	Register(&admissionsImporter{})
 25→}
 26→
 27→type admissionsImporter struct {
 28→	maxCacheAge time.Duration
 29→	requireAll  bool
 30→	platforms   string
 31→}
 32→
 33→func (a *admissionsImporter) Name() string        { return "admissions" }
 34→func (a *admissionsImporter) Description() string  { return "Import application platform membership data" }
 35→func (a *admissionsImporter) Dependencies() []string { return nil }
 36→
 37→func (a *admissionsImporter) RegisterFlags(fs *flag.FlagSet) {
 38→	fs.DurationVar(&a.maxCacheAge, "max-cache-age", 7*24*time.Hour, "maximum cache age before re-scraping")
 39→	fs.BoolVar(&a.requireAll, "require-all", false, "fail if any scraper errors")
 40→	fs.StringVar(&a.platforms, "platforms", "", "comma-separated platform keys to run (default: all)")
 41→}
 42→
 43→func (a *admissionsImporter) Run(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, fetcher *fetch.Fetcher) error {
 44→	// Load name matcher from DB.
 45→	matcher, err := namematch.Load(ctx, pool)
 46→	if err != nil {
 47→		return fmt.Errorf("admissions: load matcher: %w", err)
 48→	}
 49→
 50→	// Initialize headless browser.
 51→	browser, err := scraper.New()
 52→	if err != nil {
 53→		return fmt.Errorf("admissions: create browser: %w", err)
 54→	}
 55→	defer browser.Close()
 56→
 57→	cache := scraper.NewCache(fetcher.CacheDir(), a.maxCacheAge)
 58→	filter := parsePlatformFilter(a.platforms)
 59→	extractors := platform.All()
 60→
 61→	// Scrape (or load from cache) each platform.
 62→	platformNames, errs := scrapeAll(ctx, extractors, browser, cache, filter)
 63→
 64→	if a.requireAll && len(errs) > 0 {
 65→		return fmt.Errorf("admissions: %d extractor(s) failed: %w", len(errs), errors.Join(errs...))
 66→	}
 67→
 68→	// Match names to unit IDs and aggregate platforms per institution.
 69→	admissions, stats := aggregateAdmissions(platformNames, matcher)
 70→
 71→	// Log per-platform stats.
 72→	for _, s := range stats {
 73→		slog.Info("admissions: platform stats",
 74→			"platform", s.key,
 75→			"scraped", s.scraped,
 76→			"matched", s.matched,
 77→			"unmatched", s.unmatched,
 78→		)
 79→	}
 80→
 81→	// Build JSONB payloads and write to DB.
 82→	bulkData, err := buildAdmissionsJSON(admissions)
 83→	if err != nil {
 84→		return fmt.Errorf("admissions: build json: %w", err)
 85→	}
 86→
 87→	if err := dbutil.BulkSetAdmissions(ctx, pool, bulkData); err != nil {
 88→		return fmt.Errorf("admissions: bulk upsert: %w", err)
 89→	}
 90→
 91→	slog.Info("admissions: complete", "institutions_updated", len(bulkData))
 92→	return nil
 93→}
 94→
 95→// parsePlatformFilter converts a comma-separated string of platform keys into
 96→// a set. An empty string means "all platforms".
 97→func parsePlatformFilter(s string) map[string]bool {
 98→	s = strings.TrimSpace(s)
 99→	if s == "" {
100→		return nil
101→	}
102→	m := make(map[string]bool)
103→	for _, k := range strings.Split(s, ",") {
104→		k = strings.TrimSpace(k)
105→		if k != "" {
106→			m[k] = true
107→		}
108→	}
109→	return m
110→}
111→
112→// scrapeAll runs each extractor (checking cache first) and returns a map of
113→// platform key → institution names. Errors from individual extractors are
114→// collected and returned separately.
115→func scrapeAll(ctx context.Context, extractors []platform.Extractor, browser *scraper.Browser, cache *scraper.Cache, filter map[string]bool) (map[string][]string, []error) {
116→	result := make(map[string][]string)
117→	var errs []error
118→
119→	for _, ext := range extractors {
120→		key := ext.Key()
121→		if filter != nil && !filter[key] {
122→			slog.Debug("admissions: skipping platform (filtered)", "platform", key)
123→			continue
124→		}
125→
126→		names, err := loadOrScrape(ctx, ext, browser, cache)
127→		if err != nil {
128→			slog.Warn("admissions: extractor failed", "platform", key, "error", err)
129→			errs = append(errs, fmt.Errorf("%s: %w", key, err))
130→			continue
131→		}
132→
133→		result[key] = names
134→		slog.Info("admissions: scraped", "platform", key, "institutions", len(names))
135→	}
136→
137→	return result, errs
138→}
139→
140→// loadOrScrape attempts to load cached results; on miss or stale, runs the
141→// extractor and saves the result to cache.
142→func loadOrScrape(ctx context.Context, ext platform.Extractor, browser *scraper.Browser, cache *scraper.Cache) ([]string, error) {
143→	names, err := cache.Load(ext.Key())
144→	if err == nil {
145→		slog.Debug("admissions: cache hit", "platform", ext.Key(), "institutions", len(names))
146→		return names, nil
147→	}
148→
149→	names, err = ext.Extract(ctx, browser)
150→	if err != nil {
151→		return nil, err
152→	}
153→
154→	if saveErr := cache.Save(ext.Key(), names); saveErr != nil {
155→		slog.Warn("admissions: cache save failed", "platform", ext.Key(), "error", saveErr)
156→	}
157→
158→	return names, nil
159→}
160→
161→// platformStat tracks scrape/match statistics for a single platform.
162→type platformStat struct {
163→	key       string
164→	scraped   int
165→	matched   int
166→	unmatched int
167→}
168→
169→// aggregateAdmissions matches institution names from each platform to unit IDs
170→// and builds a map of unitID → sorted platform keys.
171→func aggregateAdmissions(platformNames map[string][]string, matcher *namematch.Matcher) (map[string][]string, []platformStat) {
172→	byUnit := make(map[string]map[string]bool)
173→	var stats []platformStat
174→
175→	// Process platforms in sorted order for deterministic output.
176→	keys := make([]string, 0, len(platformNames))
177→	for k := range platformNames {
178→		keys = append(keys, k)
179→	}
180→	sort.Strings(keys)
181→
182→	for _, key := range keys {
183→		names := platformNames[key]
184→		s := platformStat{key: key, scraped: len(names)}
185→
186→		for _, name := range names {
187→			unitID, ok := matcher.Match(name)
188→			if !ok {
189→				s.unmatched++
190→				slog.Debug("admissions: unmatched", "platform", key, "name", name)
191→				continue
192→			}
193→			s.matched++
194→			if byUnit[unitID] == nil {
195→				byUnit[unitID] = make(map[string]bool)
196→			}
197→			byUnit[unitID][key] = true
198→		}
199→		stats = append(stats, s)
200→	}
201→
202→	// Convert sets to sorted slices.
203→	result := make(map[string][]string, len(byUnit))
204→	for unitID, keySet := range byUnit {
205→		sorted := make([]string, 0, len(keySet))
206→		for k := range keySet {
207→			sorted = append(sorted, k)
208→		}
209→		sort.Strings(sorted)
210→		result[unitID] = sorted
211→	}
212→
213→	return result, stats
214→}
215→
216→// admissionsPayload is the JSON structure stored in the admissions column.
217→type admissionsPayload struct {
218→	Applications []string `json:"applications"`
219→}
220→
221→// buildAdmissionsJSON converts the aggregated map into serialized JSON
222→// suitable for BulkSetAdmissions.
223→func buildAdmissionsJSON(admissions map[string][]string) (map[string][]byte, error) {
224→	result := make(map[string][]byte, len(admissions))
225→	for unitID, platforms := range admissions {
226→		payload := admissionsPayload{Applications: platforms}
227→		data, err := json.Marshal(payload)
228→		if err != nil {
229→			return nil, fmt.Errorf("marshal %s: %w", unitID, err)
230→		}
231→		result[unitID] = data
232→	}
233→	return result, nil
234→}
