package deadlines

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"regexp"
	"strings"
	"time"
	"unicode"
)

const (
	bigfutureBaseURL = "https://bigfuture.collegeboard.org/colleges/"
	bigfuturePageType = "bigfuture"
)

// BigFutureData holds the admissions-related fields from BigFuture's
// __NEXT_DATA__ JSON (props.pageProps.collegeData).
type BigFutureData struct {
	OrgID                        string   `json:"orgId"`
	DICode                       string   `json:"diCode"`
	IPEDSId                      string   `json:"ipedsId"`
	EarlyDecision                bool     `json:"earlyDecision"`
	EarlyDecisionDate            string   `json:"earlyDecisionDate"`
	EarlyActionDate              string   `json:"earlyActionDate"`
	RegularDecisionDate          string   `json:"regularDecisionDate"`
	NotificationDate             string   `json:"notificationDate"`
	ResponseDeadline             string   `json:"responseDeadline"`
	FinancialAidRegularDeadline  string   `json:"financialAidApplicationRegularDeadline"`
	FinancialAidPriorityDeadline string   `json:"financialAidApplicationPriorityDeadline"`
	ApplicationSiteURL           string   `json:"applicationSiteUrl"`
	ApplicationsAccepted         []string `json:"applicationsAccepted"`
}

// nextDataEnvelope mirrors the __NEXT_DATA__ JSON structure down to collegeData.
type nextDataEnvelope struct {
	Props struct {
		PageProps struct {
			CollegeData BigFutureData `json:"collegeData"`
		} `json:"pageProps"`
	} `json:"props"`
}

// BigFutureURL returns the full BigFuture URL for a given slug.
func BigFutureURL(slug string) string {
	return bigfutureBaseURL + slug
}

// FetchPage performs an HTTP GET to fetch a BigFuture college page and returns
// the raw HTML bytes.
func FetchPage(ctx context.Context, client *http.Client, slug string) ([]byte, int, error) {
	url := BigFutureURL(slug)

	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return nil, 0, fmt.Errorf("deadlines: bigfuture: create request %s: %w", slug, err)
	}
	req.Header.Set("User-Agent", "Kapow/1.0 (+https://github.com/ketang/kapow)")
	req.Header.Set("Accept", "text/html")

	resp, err := client.Do(req)
	if err != nil {
		return nil, 0, fmt.Errorf("deadlines: bigfuture: fetch %s: %w", slug, err)
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, resp.StatusCode, fmt.Errorf("deadlines: bigfuture: read body %s: %w", slug, err)
	}

	if resp.StatusCode != http.StatusOK {
		return nil, resp.StatusCode, fmt.Errorf("deadlines: bigfuture: %s returned status %d", slug, resp.StatusCode)
	}

	return body, resp.StatusCode, nil
}

var (
	nextDataStart = []byte(`<script id="__NEXT_DATA__" type="application/json">`)
	nextDataEnd   = []byte(`</script>`)
)

// ParseNextData extracts the __NEXT_DATA__ JSON from BigFuture HTML and
// returns the parsed college data.
func ParseNextData(html []byte) (*BigFutureData, error) {
	startIdx := bytes.Index(html, nextDataStart)
	if startIdx < 0 {
		return nil, fmt.Errorf("deadlines: bigfuture: __NEXT_DATA__ script tag not found")
	}
	jsonStart := startIdx + len(nextDataStart)

	endIdx := bytes.Index(html[jsonStart:], nextDataEnd)
	if endIdx < 0 {
		return nil, fmt.Errorf("deadlines: bigfuture: __NEXT_DATA__ closing script tag not found")
	}

	jsonBytes := html[jsonStart : jsonStart+endIdx]

	var envelope nextDataEnvelope
	if err := json.Unmarshal(jsonBytes, &envelope); err != nil {
		return nil, fmt.Errorf("deadlines: bigfuture: parse __NEXT_DATA__ JSON: %w", err)
	}

	data := envelope.Props.PageProps.CollegeData
	return &data, nil
}

// ToDeadlineData converts BigFuture data into the canonical DeadlineData format.
// The year parameter is the admission cycle year (e.g., 2026 for Fall 2026 entry).
func ToDeadlineData(bf *BigFutureData, year int) DeadlineData {
	sourceURL := BigFutureURL(slugFromOrgID(bf.OrgID, bf.DICode))
	now := time.Now().UTC().Format(time.RFC3339)

	dd := DeadlineData{
		Plans:            make(map[string]DeadlinePlan),
		HasEarlyDecision: bf.EarlyDecision,
		HasEarlyAction:   bf.EarlyActionDate != "" && bf.EarlyActionDate != "null",
		SourceURLs:       []string{sourceURL},
		ExtractedAt:      now,
		BigfutureID:      bf.OrgID,
	}

	// Early Decision
	if bf.EarlyDecision && bf.EarlyDecisionDate != "" {
		if d := convertDate(bf.EarlyDecisionDate, year); d != "" {
			dd.Plans[PlanEarlyDecision1] = DeadlinePlan{
				Deadline:   d,
				Binding:    true,
				SourceURL:  sourceURL,
				Confidence: "medium",
			}
		}
	}

	// Early Action
	if bf.EarlyActionDate != "" {
		if d := convertDate(bf.EarlyActionDate, year); d != "" {
			dd.Plans[PlanEarlyAction] = DeadlinePlan{
				Deadline:   d,
				SourceURL:  sourceURL,
				Confidence: "medium",
			}
		}
	}

	// Regular Decision
	if bf.RegularDecisionDate != "" {
		plan := DeadlinePlan{
			SourceURL:  sourceURL,
			Confidence: "medium",
		}
		if d := convertDate(bf.RegularDecisionDate, year+1); d != "" {
			plan.Deadline = d
		}
		// Notification date goes on the regular plan.
		if d := convertDate(bf.NotificationDate, year+1); d != "" {
			plan.Notification = d
		}
		if plan.Deadline != "" || plan.Notification != "" {
			dd.Plans[PlanRegular] = plan
		}
	}

	return dd
}

// convertDate converts a BigFuture date string (MM/DD/9999) to YYYY-MM-DD
// using the given year. Returns empty string for null, empty, or unparseable dates.
func convertDate(s string, year int) string {
	s = strings.TrimSpace(s)
	if s == "" || s == "null" {
		return ""
	}

	// Expected format: MM/DD/YYYY (where YYYY is often 9999).
	parts := strings.Split(s, "/")
	if len(parts) != 3 {
		return ""
	}

	month := parts[0]
	day := parts[1]

	// Validate month and day are numeric and in range.
	if len(month) < 1 || len(month) > 2 || len(day) < 1 || len(day) > 2 {
		return ""
	}

	return fmt.Sprintf("%04d-%s-%s", year, zeroPad(month), zeroPad(day))
}

// zeroPad ensures a 1-2 digit string is zero-padded to 2 digits.
func zeroPad(s string) string {
	if len(s) == 1 {
		return "0" + s
	}
	return s
}

// slugFromOrgID is a fallback slug builder when we only have IDs, not a name.
func slugFromOrgID(orgID, diCode string) string {
	if orgID != "" {
		return orgID
	}
	return diCode
}

var slugReplacer = regexp.MustCompile(`[^a-z0-9]+`)

// SlugFromName converts an institution name to a BigFuture-style kebab-case slug.
func SlugFromName(name string) string {
	// Lowercase.
	s := strings.ToLower(name)

	// Remove apostrophes and periods (BigFuture strips these rather than
	// replacing with hyphens).
	s = strings.NewReplacer("'", "", "'", "", ".", "").Replace(s)

	// Replace any run of non-alphanumeric characters with a single hyphen.
	s = slugReplacer.ReplaceAllString(s, "-")

	// Trim leading/trailing hyphens.
	s = strings.Trim(s, "-")

	// Strip any remaining non-ASCII (safety net).
	s = strings.Map(func(r rune) rune {
		if r > unicode.MaxASCII {
			return -1
		}
		return r
	}, s)

	return s
}

package deadlines

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"

	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/ketang/kapow/tools/kapow/internal/dbutil"
)

const (
	themeAdmissions  = "ADMISSIONS"
	datakeyDeadlines = "deadlines"
)

// StoreScrapedPage inserts a row into search_base.scraped_page and returns the
// generated id.
func StoreScrapedPage(ctx context.Context, pool *pgxpool.Pool, p *ScrapedPageParams) (int64, error) {
	const sql = `
INSERT INTO search_base.scraped_page (
    unit_id, page_type, url, content_text, content_html,
    api_response, http_status, content_hash
) VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
RETURNING id`

	var id int64
	err := pool.QueryRow(ctx, sql,
		p.UnitID, p.PageType, p.URL, p.ContentText, p.ContentHTML,
		p.APIResponse, p.HTTPStatus, p.ContentHash,
	).Scan(&id)
	if err != nil {
		return 0, fmt.Errorf("deadlines: store scraped page %s/%s: %w", p.UnitID, p.PageType, err)
	}
	return id, nil
}

// UpsertDeadlines marshals data as JSON and upserts it into the annual_dataset
// table with theme=ADMISSIONS and datakey=deadlines.
func UpsertDeadlines(ctx context.Context, pool *pgxpool.Pool, unitID string, year int, data DeadlineData) error {
	raw, err := json.Marshal(data)
	if err != nil {
		return fmt.Errorf("deadlines: marshal data for %s/%d: %w", unitID, year, err)
	}
	ads := &dbutil.AnnualDataset{
		UnitID:  unitID,
		Year:    year,
		Theme:   themeAdmissions,
		Datakey: datakeyDeadlines,
		Data:    raw,
	}
	if err := dbutil.UpsertAnnualDataset(ctx, pool, ads); err != nil {
		return fmt.Errorf("deadlines: upsert deadlines %s/%d: %w", unitID, year, err)
	}
	return nil
}

// LoadExistingDeadlines queries the annual_dataset table for existing deadline
// data. Returns a zero-value DeadlineData and nil error if no row is found.
func LoadExistingDeadlines(ctx context.Context, pool *pgxpool.Pool, unitID string, year int) (DeadlineData, error) {
	const sql = `
SELECT data FROM search_base.annual_dataset
WHERE unit_id = $1 AND year = $2 AND theme = $3 AND datakey = $4`

	var raw []byte
	err := pool.QueryRow(ctx, sql, unitID, year, themeAdmissions, datakeyDeadlines).Scan(&raw)
	if err != nil {
		if errors.Is(err, pgx.ErrNoRows) {
			return DeadlineData{}, nil
		}
		return DeadlineData{}, fmt.Errorf("deadlines: load existing %s/%d: %w", unitID, year, err)
	}

	var data DeadlineData
	if err := json.Unmarshal(raw, &data); err != nil {
		return DeadlineData{}, fmt.Errorf("deadlines: unmarshal existing %s/%d: %w", unitID, year, err)
	}
	return data, nil
}

