package main

import (
	"os"
	"path/filepath"
	"testing"
)

func TestBigfutureImporterRegistered(t *testing.T) {
	imp := Get("deadlines-bigfuture")
	if imp == nil {
		t.Fatal("deadlines-bigfuture importer not registered")
	}
	if imp.Name() != "deadlines-bigfuture" {
		t.Errorf("Name() = %q, want %q", imp.Name(), "deadlines-bigfuture")
	}
	if imp.Description() == "" {
		t.Error("Description() should not be empty")
	}
	deps := imp.Dependencies()
	if len(deps) != 1 || deps[0] != "nces" {
		t.Errorf("Dependencies() = %v, want [nces]", deps)
	}
}

func TestReadSlugFile(t *testing.T) {
	content := `# comment line
harvard-university
mit

# another comment
stanford-university
`
	dir := t.TempDir()
	path := filepath.Join(dir, "slugs.txt")
	if err := os.WriteFile(path, []byte(content), 0644); err != nil {
		t.Fatal(err)
	}

	slugs, err := readSlugFile(path)
	if err != nil {
		t.Fatalf("readSlugFile: %v", err)
	}

	want := []string{"harvard-university", "mit", "stanford-university"}
	if len(slugs) != len(want) {
		t.Fatalf("got %d slugs, want %d", len(slugs), len(want))
	}
	for i, s := range slugs {
		if s != want[i] {
			t.Errorf("slug[%d] = %q, want %q", i, s, want[i])
		}
	}
}

func TestReadSlugFileMissing(t *testing.T) {
	_, err := readSlugFile("/nonexistent/file.txt")
	if err == nil {
		t.Fatal("expected error for missing file")
	}
}

